output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?god ?godLabel WHERE {
  VALUES ?god {
    wd:Q5415 wd:Q5553 wd:Q2702 wd:Q5854 wd:Q7211 wd:Q312
  }
  OPTIONAL {
    ?god rdfs:label ?godLabel .
    FILTER(langMatches(lang(?godLabel) , "en"))
  }
}

